Еве ја имплементацијата на класата `NumArray`:

```
класа NumArray {
    приватен int[] префикс;

    јавна NumArray(int[] nums) {
        префикс = нов int[nums.length];
        за (int i = 0; i < nums.length; i++) {
            ако (i == 0) {
                префикс[i] = број[i];
            } друго {
                префикс[i] = префикс[i-1] + броеви[i];
            }
        }
    }

    public int sumRange (int лево, int десно) {
        ако (лево == 0) {
            вратен префикс[десно];
        } друго {
            вратен префикс[десно] - префикс[лево-1];
        }
    }
}
```

